/**
 * MedX zindex theme token runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Stacking order for dialogs, toasts, and tooltips.
 */
const ZINDEX_TOKENS = Object.freeze({
  primary: { value: "theme-zindex-primary", scope: "theme" },
  secondary: { value: "theme-zindex-secondary", scope: "theme" },
  muted: { value: "theme-zindex-muted", scope: "theme" },
  accent: { value: "theme-zindex-accent", scope: "theme" },
  surface: { value: "theme-zindex-surface", scope: "theme" },
});

const ZINDEX_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const ZINDEX_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const zindexRegistry = new Map();
const ZINDEX_listeners = new Set();
let ZINDEX_seq = 0;

function createZindexId(prefix = "medx-theme-zindex") {
  ZINDEX_seq += 1;
  return `${prefix}-${ZINDEX_seq}`;
}

function registerZindex(config = {}) {
  const entryId = config.id ?? createZindexId();
  const preset = ZINDEX_PRESETS[config.preset ?? "default"] ?? ZINDEX_PRESETS.default;
  const token = ZINDEX_TOKENS[config.token ?? preset.token] ?? ZINDEX_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: ZINDEX_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  zindexRegistry.set(entryId, entry);
  notifyZindexListeners("register", entry);
  return entry;
}

function updateZindex(id, patch = {}) {
  const entry = zindexRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyZindexListeners("update", entry);
  return entry;
}

function resolveZindex(id) {
  const entry = zindexRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listZindexEntries(filter = {}) {
  let items = Array.from(zindexRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onZindexEvent(listener) {
  ZINDEX_listeners.add(listener);
  return () => ZINDEX_listeners.delete(listener);
}

function notifyZindexListeners(type, entry) {
  for (const listener of ZINDEX_listeners) {
    try {
      listener({ type, entry, registrySize: zindexRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:theme:zindex] listener error", err.message);
    }
  }
}

function getZindexMetrics() {
  const items = listZindexEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(ZINDEX_TOKENS).length,
    presets: Object.keys(ZINDEX_PRESETS).length,
  };
}

async function runMedxZindex() {
  console.log("[medx:ui:theme:zindex] runtime initialized");
  console.log(`[medx:ui:theme:zindex] tokens=${Object.keys(ZINDEX_TOKENS).length} presets=${Object.keys(ZINDEX_PRESETS).length}`);

  const events = [];
  onZindexEvent((e) => events.push(e.type));

  const domains = Object.keys(ZINDEX_SUPPLY_CHAIN);
  const presets = Object.keys(ZINDEX_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerZindex({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "theme/zindex" },
    });
  }

  const first = listZindexEntries()[0];
  if (first) updateZindex(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getZindexMetrics();
  const resolved = first ? resolveZindex(first.id) : null;

  console.log(`[medx:ui:theme:zindex] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:theme:zindex] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:theme:zindex] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:theme:zindex] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:theme:zindex] bootstrap complete");
}

module.exports = runMedxZindex;
